SELECT count(*) FROM hm_query.onboarding_flat

    AND supplier_id = #{supplierId}
    AND business_type = #{businessType}
    AND state_id = #{stateId}
    AND applicant_name LIKE CONCAT('%', #{applicantName}, '%')
    AND business_name LIKE CONCAT('%', #{businessName}, '%')
    AND (applicant_name LIKE CONCAT('%', #{q}, '%') OR business_name LIKE CONCAT('%', #{q}, '%') OR supplier_id LIKE CONCAT('%', #{q}, '%'))

SELECT onboarding_id as "id", supplier_id as "supplierId", applicant_name as "applicantName", business_name as "businessName", business_type as "businessType", training_progress as "trainingProgress", state_id as "stateId", flow_id as "flowId", submitted_at as "submittedAt", created_time as "createdTime" FROM hm_query.onboarding_flat
AND supplier_id = #{supplierId} AND business_type = #{businessType} AND state_id = #{stateId} AND applicant_name LIKE CONCAT('%', #{applicantName}, '%') AND business_name LIKE CONCAT('%', #{businessName}, '%') AND (applicant_name LIKE CONCAT('%', #{q}, '%') OR business_name LIKE CONCAT('%', #{q}, '%') OR supplier_id LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
